mapper.select:
select ID,RVNM,BSNM,STARTPOINT,ENDPOINT,SHAPELENG,GN,TYPEID,DENGJI,CITYNAME,NT,ORDERBYID,LGTD,LTTD,SWPID,TGTQPID,GQPID,EXPID,WSJPID from HD_BASE_B

    shapepath is not null

        AND ID IN

            #{city}



        AND RVNM IN

            #{city}



        and (RVNM like concat('%',concat(#{KEY},'%'))  or GN like  concat('%',concat(#{KEY},'%')) or BSNM like  concat('%',concat(#{KEY},'%')) or CITYNAME like  concat('%',concat(#{KEY},'%')))


        and TYPEID =#{PATHNAME}


order by ORDERBYID
